#include <bits/stdc++.h>using namespace std;#define int long long int#define all(x) x.begin(), x.end() void solve() {    int n; cin >> n;    string s, p; cin >> s >> p;    vector<int> dp(n + 1, 1e10), dp2(n + 1, 1e10);    dp[0] = 0;    for (int i = 1; i <= n; i++) {        int x;        if (s[i - 1] == p[i - 1]) x = 0;        else x = 1;        dp[i] = min(dp[i], dp[i - 1] + x);        if (i >= 2) {            int x, y;            if (s[i - 1] == s[i - 2]) x = 0;            else x = 1;            if (p[i - 2] == p[i - 1]) y = 0;            else y = 1;            dp[i] = min(dp[i], dp[i - 2] + x + y);        }    }    cout << dp[n] << endl;}int32_t main() {    ios_base::sync_with_stdio(0); cin.tie(0);    int t = 1; cin >> t;    while (t--) solve();    return 0;}